<?php require __DIR__."/vendor/autoload.php"; $app = require_once __DIR__."/bootstrap/app.php"; $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class); $kernel->bootstrap(); $user = App\Models\User::first(); $startTime = microtime(true); DB::transaction(function () use ($user) { $idsToKeep = DB::table("password_history")->where("user_id", $user->id)->orderByDesc("created_at")->limit(5)->pluck("id"); DB::table("password_history")->where("user_id", $user->id)->whereNotIn("id", $idsToKeep)->delete(); }); echo "Archive logic done in ".(microtime(true) - $startTime)." sec\n"; 